-- Seed operational clients from the May 2026 spreadsheets.
-- Safe to re-run: the insert skips clients that already exist by name.

BEGIN;

CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- Teams needed by this seed
INSERT INTO public.teams (id, name)
VALUES
  ('0469e3aa-5b34-42e2-b89d-f412efaa27ba', 'Equipe 7'),
  ('38c9028d-856d-481e-95c9-bb2eb8b459f5', 'Tropa de Elite')
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name;

-- Resolve profile ids by the names used in the spreadsheets.
CREATE OR REPLACE FUNCTION public.resolve_profile_id_by_name(p_name text)
RETURNS uuid
LANGUAGE sql
STABLE
AS $$
  SELECT p.id
  FROM public.profiles p
  WHERE lower(coalesce(p.full_name, '')) = lower(trim(coalesce(p_name, '')))
     OR lower(coalesce(p.full_name, '')) LIKE '%' || lower(trim(coalesce(p_name, ''))) || '%'
  ORDER BY CASE WHEN lower(coalesce(p.full_name, '')) = lower(trim(coalesce(p_name, ''))) THEN 0 ELSE 1 END,
           length(coalesce(p.full_name, '')),
           p.full_name
  LIMIT 1;
$$;

-- Open CRUD for the client tables and the tables touched by client deletion.
DO $$
DECLARE
  tbl text;
BEGIN
  FOREACH tbl IN ARRAY ARRAY[
    'operational_clients',
    'crm_events',
    'client_files',
    'ad_creatives',
    'client_activity_tracking',
    'exec_cards',
    'projects',
    'crisis_manual_clients',
    'exec_card_sync_blocks'
  ]
  LOOP
    IF to_regclass(format('public.%I', tbl)) IS NOT NULL THEN
      EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', tbl);
      EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', 'view_public_' || tbl, tbl);
      EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', 'insert_public_' || tbl, tbl);
      EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', 'update_public_' || tbl, tbl);
      EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', 'delete_public_' || tbl, tbl);
      EXECUTE format(
        'CREATE POLICY %I ON public.%I FOR SELECT TO public USING (true)',
        'view_public_' || tbl,
        tbl
      );
      EXECUTE format(
        'CREATE POLICY %I ON public.%I FOR INSERT TO public WITH CHECK (true)',
        'insert_public_' || tbl,
        tbl
      );
      EXECUTE format(
        'CREATE POLICY %I ON public.%I FOR UPDATE TO public USING (true) WITH CHECK (true)',
        'update_public_' || tbl,
        tbl
      );
      EXECUTE format(
        'CREATE POLICY %I ON public.%I FOR DELETE TO public USING (true)',
        'delete_public_' || tbl,
        tbl
      );
      EXECUTE format(
        'GRANT SELECT, INSERT, UPDATE, DELETE ON public.%I TO anon, authenticated, service_role',
        tbl
      );
    END IF;
  END LOOP;
END $$;

DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM pg_publication WHERE pubname = 'supabase_realtime') THEN
    BEGIN
      EXECUTE 'ALTER PUBLICATION supabase_realtime ADD TABLE public.operational_clients';
    EXCEPTION
      WHEN duplicate_object THEN NULL;
    END;
  END IF;
END $$;

-- Delete helper used by the CRM UI.
CREATE OR REPLACE FUNCTION public.delete_operational_client_cascade(p_client_id UUID)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  IF to_regclass('public.client_activity_tracking') IS NOT NULL THEN
    EXECUTE 'DELETE FROM public.client_activity_tracking WHERE client_id = $1' USING p_client_id;
  END IF;
  IF to_regclass('public.client_files') IS NOT NULL THEN
    EXECUTE 'DELETE FROM public.client_files WHERE client_id = $1' USING p_client_id;
  END IF;
  IF to_regclass('public.ad_creatives') IS NOT NULL THEN
    EXECUTE 'DELETE FROM public.ad_creatives WHERE client_id = $1' USING p_client_id;
  END IF;
  IF to_regclass('public.crm_events') IS NOT NULL THEN
    EXECUTE 'DELETE FROM public.crm_events WHERE client_id = $1' USING p_client_id;
  END IF;
  IF to_regclass('public.projects') IS NOT NULL THEN
    EXECUTE 'DELETE FROM public.projects WHERE client_id = $1' USING p_client_id;
  END IF;
  IF to_regclass('public.exec_cards') IS NOT NULL THEN
    EXECUTE 'UPDATE public.exec_cards SET client_id = NULL WHERE client_id = $1' USING p_client_id;
  END IF;
  IF to_regclass('public.exec_card_sync_blocks') IS NOT NULL THEN
    EXECUTE 'DELETE FROM public.exec_card_sync_blocks WHERE client_id = $1' USING p_client_id;
  END IF;
  IF to_regclass('public.crisis_manual_clients') IS NOT NULL THEN
    EXECUTE 'DELETE FROM public.crisis_manual_clients WHERE source_operational_client_id = $1::text OR id = $1::text' USING p_client_id;
  END IF;
  DELETE FROM public.operational_clients WHERE id = p_client_id;
END;
$$;

REVOKE ALL ON FUNCTION public.delete_operational_client_cascade(UUID) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.delete_operational_client_cascade(UUID) TO anon, authenticated, service_role;

